#include<bits/stdc++.h>
using namespace std;
long long n,m,k;
long long fa[400010],siz[400010];
struct Stack
{
    long long lstmax,lstmin,lsttag,pos,treeid;
}s[3200010];
long long top;
struct query
{
    long long l,r;
};
vector<query> t[600010];
struct segment_tree
{
    struct node
    {
        long long l,r,max1,min1;
        long long lson,rson;
        long long tag;
    }a[600010];
    long long cnt,id;
    segment_tree():cnt(0){}
    void pushup(long long x)
    {
        a[x].max1=max(a[a[x].lson].max1,a[a[x].rson].max1);
        a[x].min1=min(a[a[x].lson].min1,a[a[x].rson].min1);
    }
    void pushdown(long long x)
    {
        long long mid=(a[x].l+a[x].r)>>1;
        long long ls=a[x].lson,rs=a[x].rson;
        long long tg=a[x].tag;
        if(tg==-1||tg==1e9)
        {
            return;
        }
        s[++top]=(Stack){a[x].max1,a[x].min1,a[x].tag,x,id};
        s[++top]=(Stack){a[ls].max1,a[ls].min1,a[ls].tag,ls,id};
        s[++top]=(Stack){a[rs].max1,a[rs].min1,a[rs].tag,rs,id};
        a[ls].max1=max(a[ls].max1,tg);
        a[ls].min1=min(a[ls].min1,tg);
        a[rs].max1=max(a[rs].max1,tg);
        a[rs].min1=min(a[rs].min1,tg);
        if(id==1)
        {
            a[ls].tag=max(a[ls].tag,tg);
            a[rs].tag=max(a[rs].tag,tg);
            a[x].tag=-1;
        }
        else
        {
            a[ls].tag=min(a[ls].tag,tg);
            a[rs].tag=min(a[rs].tag,tg);
            a[x].tag=1e9;
        }
    }
    long long init(long long l,long long r)
    {
        long long x=++cnt,mid=(l+r)>>1;
        a[x].l=l;
        a[x].r=r;
        if(id==1)
        {
            a[x].tag=-1;
        }
        else
        {
            a[x].tag=1e9;
        }
        if(l==r)
        {
            a[x].max1=0;
            a[x].min1=1e9;
            return x;
        }
        a[x].lson=init(l,mid);
        a[x].rson=init(mid+1,r);
        pushup(x);
        return x;
    }
    void update(long long x,long long l,long long r,long long z)
    {
        if(a[x].l>r||a[x].r<l)
        {
            return;
        }
        s[++top]=(Stack){a[x].max1,a[x].min1,a[x].tag,x,id};
        if(l<=a[x].l&&a[x].r<=r)
        {
            a[x].max1=max(a[x].max1,z);
            a[x].min1=min(a[x].min1,z);
            if(id==1)
            {
                a[x].tag=max(a[x].tag,z);
            }
            else
            {
                a[x].tag=min(a[x].tag,z);
            }
            return;
        }
        pushdown(x);
        update(a[x].lson,l,r,z);
        update(a[x].rson,l,r,z);
        pushup(x);
    }
    long long getmax(long long x,long long l,long long r)
    {
        if(a[x].l>r||a[x].r<l)
        {
            return 0;
        }
        if(a[x].l>=l&&a[x].r<=r)
        {
            return a[x].max1;
        }
        pushdown(x);
        return max(getmax(a[x].lson,l,r),getmax(a[x].rson,l,r));
    }
    long long getmin(long long x,long long l,long long r)
    {
        if(a[x].l>r||a[x].r<l)
        {
            return 1e9;
        }
        if(a[x].l>=l&&a[x].r<=r)
        {
            return a[x].min1;
        }
        pushdown(x);
        return min(getmin(a[x].lson,l,r),getmin(a[x].rson,l,r));
    }
}t1,t2;
void back(Stack x)
{
    if(x.treeid==1)
    {
        t1.a[x.pos].tag=x.lsttag;
        t1.a[x.pos].max1=x.lstmax;
        t1.a[x.pos].min1=x.lstmin;
    }
    else
    {
        t2.a[x.pos].tag=x.lsttag;
        t2.a[x.pos].max1=x.lstmax;
        t2.a[x.pos].min1=x.lstmin;
    }
}
void update(long long x,long long l,long long r,long long L,long long R,query v)
{
    if(L>R||l>R||L>r)
    {
        return;
    }
    if(L<=l&&r<=R)
    {
        t[x].push_back(v);
        return;
    }
    long long mid=(l+r)>>1;
    update(x<<1,l,mid,L,R,v);
    update(x<<1|1,mid+1,r,L,R,v);
}
void solve(long long x,long long l,long long r)
{
    long long flag=1;
    long long lst=top;
    for(auto i:t[x])
    {
        if(i.l!=i.r)
        {
            long long v1=t1.getmax(1,i.r,i.r);
            long long v2=t2.getmin(1,i.l,i.l);
            if(i.l<v1||i.r>v2)
            {
                for(long long i=l;i<=r;i++)
                {
                    printf("No\n");
                }
                flag=0;
                break;
            }
            t1.update(1,i.l,i.r-1,i.l);
            t2.update(1,i.l+1,i.r,i.r);
        }
    }
    if(flag)
    {
        if(l==r)
        {
            printf("Yes\n");
        }
        else
        {
            long long mid=(l+r)>>1;
            solve(x<<1,l,mid);
            solve(x<<1|1,mid+1,r);
        }
    }
    while(top>lst)
    {
        back(s[top]);
        top--;
    }
}
long long pos[500010];
struct node
{
    long long l,r,l1,r1;
};
int main()
{
    t1.id=1;
    t2.id=2;
    long long n,q;
    scanf("%lld%lld",&n,&q);
    long long tot=0;
    vector<node> v;
    for(long long i=1;i<=q;i++)
    {
        long long op,x,y;
        scanf("%lld%lld",&op,&x);
        if(op==1)
        {
            scanf("%lld",&y);
            v.push_back((node){x,y,i,q});
            pos[i]=tot++;
        }
        else
        {
            v[pos[x]].r1=i-1;
        }
    }
    for(auto i:v)
    {
        update(1,1,q,i.l1,i.r1,(query){i.l,i.r});
    }
    t1.init(1,n);
    t2.init(1,n);
    solve(1,1,q);
    return 0;
}
